"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[1366],{2649(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>a,toc:()=>l});var i=t(4848),s=t(8453);const o={},r="Chapter 5: The Wild Growth of AI and Wintel's Blind Spot",a={id:"GameVictory/\u7b2c\u4e94\u7ae0_AI\u7684\u91ce\u883b\u751f\u9577\u8207Wintel\u7684\u76f2\u5340_v2",title:"Chapter 5: The Wild Growth of AI and Wintel's Blind Spot",description:"In 2025, a Stanford PhD student sits in her lab, preparing to train her language model.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u4e94\u7ae0_AI\u7684\u91ce\u883b\u751f\u9577\u8207Wintel\u7684\u76f2\u5340_v2.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u4e94\u7ae0_AI\u7684\u91ce\u883b\u751f\u9577\u8207Wintel\u7684\u76f2\u5340_v2",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e94\u7ae0_AI\u7684\u91ce\u883b\u751f\u9577\u8207Wintel\u7684\u76f2\u5340_v2",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 4: Sega's Five-Million-Dollar Mercy",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u56db\u7ae0_\u4e16\u5609\u7684\u4e94\u767e\u842c\u7f8e\u5143\u5584\u6b3e_v1"},next:{title:"Chapter 6: Gabe Newell's Prison Break",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u516d\u7ae0_Gabe Newell \u7684\u8d8a\u7344\u884c\u52d5_v5"}},d={},l=[{value:"I. Motive for the Crime: Two Walls",id:"i-motive-for-the-crime-two-walls",level:2},{value:"II. The First Blind Spot: Ballmer&#39;s Cancer Theory",id:"ii-the-first-blind-spot-ballmers-cancer-theory",level:2},{value:"III. The Second Blind Spot: Intel Kills Its Own GPU",id:"iii-the-second-blind-spot-intel-kills-its-own-gpu",level:2},{value:"IV. The Great Escape",id:"iv-the-great-escape",level:2},{value:"V. Closing Arguments",id:"v-closing-arguments",level:2},{value:"VI. The Loot is Still Being Divided",id:"vi-the-loot-is-still-being-divided",level:2}];function h(e){const n={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"chapter-5-the-wild-growth-of-ai-and-wintels-blind-spot",children:"Chapter 5: The Wild Growth of AI and Wintel's Blind Spot"})}),"\n",(0,i.jsx)(n.p,{children:"In 2025, a Stanford PhD student sits in her lab, preparing to train her language model."}),"\n",(0,i.jsx)(n.p,{children:"She opens her laptop\u2014a MacBook running macOS. She connects to a remote GPU cluster\u2014eight servers, each slotted with eight NVIDIA H100s, running Ubuntu Linux. Her code is written in Python, the framework is PyTorch, the underlying layer uses CUDA, and the compilers, schedulers, drivers, and OS kernels\u2014from the moment she hits Enter to when the first gradient starts returning, not a single line of the software stack she touches belongs to Microsoft."}),"\n",(0,i.jsx)(n.p,{children:"She doesn't find this strange at all. From her first day in grad school, all tutorials, all code attached to papers, and all lab machines have been entirely Linux. Windows? That's the thing she occasionally opens to run PowerPoint."}),"\n",(0,i.jsx)(n.p,{children:"But if she were to look up and think for a moment\u2014she would bump into a very uncomfortable question."}),"\n",(0,i.jsx)(n.p,{children:"The H100 graphics card she uses was made by NVIDIA. What nourished NVIDIA as it grew? PC gamers on Windows\u2014who for twenty years bought graphics cards generation after generation for prettier visuals, sharing the R&D costs of parallel computing for NVIDIA. The GPU cluster she connects to is rented from Microsoft Azure's cloud service\u2014and over 60% of the virtual machines on Azure run Linux."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"The money that raised NVIDIA came from Windows. The infrastructure for training AI models is built on Microsoft's cloud. But AI itself\u2014its frameworks, its toolchains, its entire software ecosystem\u2014has absolutely nothing to do with Windows."})}),"\n",(0,i.jsx)(n.p,{children:"This is not an accident. It is the direct consequence of two empires making separate decisions twenty years ago\u2014one deciding not to act, and the other deciding to forbid."}),"\n",(0,i.jsx)(n.p,{children:"The one that decided not to act was Intel. The one that decided to forbid was Microsoft."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"i-motive-for-the-crime-two-walls",children:"I. Motive for the Crime: Two Walls"}),"\n",(0,i.jsx)(n.p,{children:"To understand why AI grew on Linux, you first have to understand one thing: it's not that Linux was overwhelmingly attractive, but that Windows drove people away."}),"\n",(0,i.jsx)(n.p,{children:"The method of driving them away was elegant\u2014so elegant that the people being driven away couldn't necessarily articulate what was happening."}),"\n",(0,i.jsx)(n.p,{children:"In 1993, Windows NT was released. Its core design borrowed from DEC's VMS and Carnegie Mellon University's Mach microkernel\u2014refined, rigorous, and enterprise-grade. The most crucial design decision was the x86 processor's privilege ring architecture: kernel code ran in Ring 0, possessing complete hardware access rights; applications ran in Ring 3, isolated behind an invisible wall."}),"\n",(0,i.jsx)(n.p,{children:"This was the cornerstone of security. A program running in Ring 3 could not directly touch memory mapping, could not independently operate I/O ports, and could not bypass the scheduler to seize hardware resources. If a game crashed, it wouldn't bring down the whole computer\u2014it would only die within its own fenced-off space."}),"\n",(0,i.jsx)(n.p,{children:'For ordinary users, this was a godsend. The nightmare of the DOS era, where "one game crashes, the whole machine dies," disappeared forever. The exam mentioned in Chapter 1 of fighting with CONFIG.SYS every night, along with its admission ticket, was revoked.'}),"\n",(0,i.jsx)(n.p,{children:"But on the other side of the wall stood a completely different group of people."}),"\n",(0,i.jsx)(n.p,{children:"From the late nineties to the early two-thousands, inside the physics departments, math departments, and computational linguistics labs of universities worldwide, a group of researchers was doing something that seemed to have zero commercial future\u2014feeding massive amounts of data into mathematical models to make machines learn to recognize images, translate sentences, and predict protein folding. What they needed was the most direct, lowest-level, most undisturbed access to hardware. They wanted to write kernel modules themselves, modify drivers themselves, and decide for themselves how memory was arranged and how every compute unit of the GPU was scheduled."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"To them, Windows' separation of Ring 0 and Ring 3 wasn't protection; it was an obstacle."})}),"\n",(0,i.jsx)(n.p,{children:"And Linux\u2014which also used the x86 privilege rings, and also had the Ring 0 / Ring 3 distinction\u2014did something Windows would never do: it completely opened up its kernel source code."}),"\n",(0,i.jsx)(n.p,{children:"You want to write a kernel module to directly access the GPU's registers? Write it, compile it, load it, and it takes effect immediately. You want to modify the memory manager so your training data is arranged in a specific way in physical memory? Change it, recompile the kernel, reboot, and it's done. You want NVIDIA's drivers to bypass the OS's display manager and write compute results directly back to main memory? NVIDIA's engineers could do it themselves, because they could see every line of the Linux kernel."}),"\n",(0,i.jsx)(n.p,{children:"On Windows, doing the same thing required Microsoft's cooperation\u2014modifying WDDM (Windows Display Driver Model), tweaking GPU scheduling policies, opening new kernel interfaces. But Microsoft had no motive to cooperate. In 2005, GPU computing was a sci-fi concept to Microsoft; its engineering priorities were Vista's Aero effects, DirectX 10's new shader model, and making games look prettier on Windows."}),"\n",(0,i.jsx)(n.p,{children:"The \"naked hardware access\" those researchers wanted didn't even have a checkbox on Microsoft's product roadmap."}),"\n",(0,i.jsx)(n.p,{children:"So they left."}),"\n",(0,i.jsx)(n.p,{children:"Not leaving in anger, not publishing manifestos, not organizing collective boycotts. Just quietly, lab by lab, swapping their workstations from Windows to Linux. In the mid-2000s, among the top 500 supercomputers in the world, Linux's share surged from 50% to 90%. By 2010, on the Top 500 list, Windows had fewer than ten spots left."}),"\n",(0,i.jsx)(n.p,{children:"What was running inside those supercomputers wasn't just climate modeling and gene sequencing. A small group of people was using them to do something no one thought much of at the time\u2014using GPUs for matrix multiplication."}),"\n",(0,i.jsx)(n.p,{children:"But let's be honest here\u2014this wasn't a clean-cut revolution."}),"\n",(0,i.jsx)(n.p,{children:"In the university labs of 2005, Windows didn't disappear. Professors still used it to open PowerPoint for progress reports, PhD students still used it to run MATLAB for matrix math and plotting, instrument control software like LabVIEW only had Windows versions, and the statistics department couldn't live without SPSS. Windows remained the daily driver desktop in academia, booted up for eight hours a day."}),"\n",(0,i.jsxs)(n.p,{children:["What really changed was a very quiet detail. If you walked up to those PhD students' computers and pressed the power button, you would see a menu with white text on a black background\u2014",(0,i.jsx)(n.strong,{children:"GRUB"}),". With two lines on it: Windows, Linux."]}),"\n",(0,i.jsx)(n.p,{children:"Dual boot. This was the real scene in academia in the 2000s."}),"\n",(0,i.jsx)(n.p,{children:"Windows handled the mundane: writing reports, running MATLAB for a few graphs, replying to emails, making slides. But as soon as the work entered a phase that required squeezing the hardware\u2014compiling custom kernel modules, connecting to FPGA dev boards, SSHing into the lab's GPU cluster\u2014the grad students would reboot, switching into that black terminal with no desktop effects, no start menu, just a blinking cursor."}),"\n",(0,i.jsxs)(n.p,{children:["Windows wasn't abandoned. ",(0,i.jsx)(n.strong,{children:"It was demoted."}),' Downgraded from "omnipotent operating system" to "word processor and presentation machine." And the computations that truly determined the future\u2014the work that required naked access to hardware\u2014all happened in the world after the reboot.']}),"\n",(0,i.jsxs)(n.p,{children:["Microsoft probably didn't notice this demotion. Because from the perspective of their licensing fees, that computer still had a copy of Windows installed. The numbers hadn't decreased. But power had shifted\u2014",(0,i.jsx)(n.strong,{children:"the computations deciding the technological direction of the next decade were no longer happening inside Windows."})]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"ii-the-first-blind-spot-ballmers-cancer-theory",children:"II. The First Blind Spot: Ballmer's Cancer Theory"}),"\n",(0,i.jsx)(n.p,{children:"While the researchers were quietly exiting, what did Microsoft do?"}),"\n",(0,i.jsx)(n.p,{children:"In June 2001, Microsoft CEO Steve Ballmer was interviewed by the Chicago Sun-Times. The reporter asked what he thought of Linux. His answer left the most expensive quote in tech history:"}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:'"Linux is a cancer."'})}),"\n",(0,i.jsx)(n.p,{children:"Ballmer's exact words were more precise than that\u2014he was saying the GPL licensing terms were like a cancer that would \"infect\" all intellectual property it touched. This was a legal argument, and in corporate legal circles at the time, it wasn't outrageous. But the problem wasn't the law; it was the signal."}),"\n",(0,i.jsxs)(n.p,{children:["When that sentence came out of the mouth of Microsoft's CEO, it broadcast only one signal: ",(0,i.jsx)(n.strong,{children:"Microsoft views Linux as an enemy."})]}),"\n",(0,i.jsx)(n.p,{children:"The signal was received by everyone."}),"\n",(0,i.jsxs)(n.p,{children:["Enterprise CIOs received it\u2014some companies evaluating Linux server solutions were scared off. Ballmer probably thought this was a good thing. But the signal was also received by another group: researchers writing open-source software in universities, startup teams running servers on Linux in Silicon Valley garages, and engineers writing toolchains for GPU computing. The signal they received was: ",(0,i.jsx)(n.strong,{children:"Microsoft will never cooperate with us."})]}),"\n",(0,i.jsx)(n.p,{children:"So they stopped waiting."}),"\n",(0,i.jsxs)(n.p,{children:["Between 2003 and 2007, almost all the early projects that later defined AI infrastructure chose Linux as their sole target platform. Not because the Linux desktop experience was good\u2014the Linux desktop in 2005 often couldn't even connect to Wi-Fi. But because ",(0,i.jsx)(n.strong,{children:'it was the only place where you wouldn\'t wake up one morning to find the platform owner had suddenly changed the rules, charged rent, or called you a "cancer."'})]}),"\n",(0,i.jsx)(n.p,{children:"In the same year\u20142001\u2014another team at Microsoft was handing out the first Xbox in New York's Times Square. As discussed in Chapter 3, the Xbox was a wall used to block Sony. Ballmer's \"cancer theory\" was another wall\u2014used to block Linux."}),"\n",(0,i.jsx)(n.p,{children:"Both walls successfully blocked the opponents right in front of them. But together, those two walls also locked out a continent that was just beginning to take shape."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iii-the-second-blind-spot-intel-kills-its-own-gpu",children:"III. The Second Blind Spot: Intel Kills Its Own GPU"}),"\n",(0,i.jsxs)(n.p,{children:["If Microsoft's mistake was treating Linux as an enemy, Intel's mistake was even more fatal\u2014",(0,i.jsx)(n.strong,{children:"it killed its own child."})]}),"\n",(0,i.jsx)(n.p,{children:"In 2006, NVIDIA released CUDA\u2014a set of tools allowing programmers to use C to do general-purpose computing directly on the GPU. Chapter 7 will fully detail the history and consequences of this decision. All you need to know here is one thing: at the time, nobody in the world took CUDA seriously. GPUs were for drawing triangles, not calculating matrices. Carmack didn't care, game studios didn't care, Wall Street didn't care."}),"\n",(0,i.jsx)(n.p,{children:"But Intel cared\u2014only, entirely in the wrong direction."}),"\n",(0,i.jsxs)(n.p,{children:["In 2008, Intel announced a project called ",(0,i.jsx)(n.strong,{children:"Larrabee"}),". The concept was extremely bold: a GPU based entirely on the x86 instruction set. Not an architecture requiring a proprietary language (CUDA) like NVIDIA's, not a traditional graphics pipeline design like AMD's\u2014Larrabee aimed to let programmers use the C++ they already knew, on a chip covered in dozens of small x86 cores, doing both graphics and general-purpose compute simultaneously."]}),"\n",(0,i.jsx)(n.p,{children:"If Larrabee had succeeded, history would have been completely rewritten."}),"\n",(0,i.jsx)(n.p,{children:"An x86 GPU meant Intel's entire software ecosystem\u2014compilers, debuggers, performance profilers, decades of accumulated x86 optimization experience\u2014could all be ported directly over. Developers wouldn't need to learn CUDA; they wouldn't need to rewrite their code into GPU-friendly formats. They would just write C++, and Intel's compiler would handle the rest."}),"\n",(0,i.jsxs)(n.p,{children:["More crucially: Intel was the overlord of the CPU. If it possessed a GPU at the same time, it could do something NVIDIA couldn't\u2014",(0,i.jsx)(n.strong,{children:"have the CPU and GPU share the same memory, use the same bus, and run the same instruction set."})," Today, one of the biggest bottlenecks in AI training is the data transfer between CPU and GPU. If Larrabee had succeeded, this bottleneck wouldn't exist architecturally."]}),"\n",(0,i.jsx)(n.p,{children:"NVIDIA's CUDA monopoly might never have happened."}),"\n",(0,i.jsx)(n.p,{children:"But Larrabee didn't succeed."}),"\n",(0,i.jsx)(n.p,{children:'In May 2010, Intel announced the cancellation of Larrabee as a consumer graphics card project. The official narrative was a "shift toward high-performance computing." The wreckage was renamed Xeon Phi, stuffed into the server market to linger for a few years, and then completely axed around 2017.'}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Why was it killed?"})}),"\n",(0,i.jsx)(n.p,{children:"The answer hides in Intel's financial statements. In 2010, the gross margin of Intel's CPU business exceeded 60%. The company's entire revenue structure, bonus system, and promotion paths revolved around this number. The GPU was a brand new market\u2014gross margins were uncertain, development cycles were long, it required building driver teams and ecosystems from scratch, and it would consume massive engineering resources in the short term with no visible return."}),"\n",(0,i.jsx)(n.p,{children:"In a company with 60% gross margins, asking the board to approve a short-term-loss, long-term-uncertain GPU project\u2014this wasn't a technical problem; it was a systemic problem."}),"\n",(0,i.jsx)(n.p,{children:"The killer of Larrabee inside Intel was not a villain with a recognizable name. It was the incentive structure of the entire system: every division head was protecting their own gross margin; every quarterly earnings call promised profit growth to Wall Street; every vice president knew that shifting resources from the CPU to a GPU with an uncertain future would impact their annual performance review."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:'Nobody made a "wrong decision." Everyone made the most rational decision for their own position. But all the rational decisions added up to a suicidal outcome.'})}),"\n",(0,i.jsx)(n.p,{children:"This structural suicide will appear again in Chapter 9\u2014the tragedy of Pat Gelsinger. Gelsinger returned to Intel in 2021 trying to turn the tide, but what he faced was the very karma planted when Larrabee was killed: Intel missed the GPU, missed AI, and missed an entire era. And that era was monopolized solely by NVIDIA."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"iv-the-great-escape",children:"IV. The Great Escape"}),"\n",(0,i.jsx)(n.p,{children:"When the two blind spots stacked together, the effect was this\u2014"}),"\n",(0,i.jsx)(n.p,{children:"Microsoft treating Linux as a cancer meant Windows would not actively serve the scientific toolchains running on Linux. Intel killing Larrabee meant the only hardware on the market capable of general-purpose GPU computing was NVIDIA."}),"\n",(0,i.jsx)(n.p,{children:"And NVIDIA's CUDA\u2014during that long waiting period from 2007 to 2012 when no one believed in it\u2014placed its entire bet on Linux."}),"\n",(0,i.jsx)(n.p,{children:"This wasn't an accident. CUDA's target users were researchers and HPC engineers. What did their machines run? Linux. What compiled their code? GCC. What did their workflows look like? SSHing into servers, running scripts, checking logs, tuning parameters."}),"\n",(0,i.jsx)(n.p,{children:"For NVIDIA engineers doing CUDA development on Linux versus doing it on Windows, there was a structural gap. The Linux kernel is open source\u2014NVIDIA could write its own kernel modules, bypass the OS's GPU scheduler, and let CUDA directly control every compute unit of the GPU. On Windows, the same thing had to go through the WDDM driver model, passing through an extra scheduling layer controlled by Microsoft. The latency and restrictions added by this extra layer were imperceptible when playing games; but when training a model that required thousands of GPUs to synchronize, every microsecond of overhead was magnified thousands of times."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Linux didn't win because it was easy to use. It won because it was open enough\u2014open enough to let NVIDIA do whatever it wanted without needing permission from any platform owner."})}),"\n",(0,i.jsx)(n.p,{children:"And GPU clusters were only one escape route. Another route was quieter, but had a much larger footprint."}),"\n",(0,i.jsx)(n.p,{children:"If you walked out of the Computer Science department and into the labs of the Electrical Engineering or Mechanical Engineering departments next door, you would see a different kind of computer\u2014not a desktop PC, not a server, but bare EVBs (Evaluation Boards). These palm-sized circuit boards were the brains of medical instruments, industrial robots, agricultural drones, and autonomous driving sensor modules. Their processors might be ARM or RISC-V, their memory was only a few hundred MBs, and storage was measured in GBs. What OS did they run?"}),"\n",(0,i.jsx)(n.p,{children:"100% Linux."}),"\n",(0,i.jsx)(n.p,{children:"Not because researchers favored the open-source spirit, but because there was no other choice. Microsoft had tried\u2014Windows CE, Windows Embedded, changing names several times\u2014but the Windows kernel was too bulky, licensing fees were too high, and it didn't allow you to strip the system down to just the few modules you needed. An EVB with only 256MB of RAM couldn't fit Windows, but it could run a Linux kernel stripped down to tens of MBs, plus the custom drivers and control programs you wrote yourself."}),"\n",(0,i.jsxs)(n.p,{children:["This might seem unrelated to AI, and even less related to gaming. But it had a severely underestimated consequence: ",(0,i.jsx)(n.strong,{children:'Every engineer who ever wrote a Linux driver on an EVB was someone who understood the entire pipeline "from kernel to hardware."'}),' Where did these people go later? Some founded robotics companies, some went into autonomous driving, some joined NVIDIA to write CUDA drivers, and some became the backbone of AI infrastructure teams. What they brought with them wasn\'t proficiency in a specific programming language, but an engineering intuition of "opening the lid to look inside"\u2014exactly the disappearing capability discussed in the interlude.']}),"\n",(0,i.jsx)(n.p,{children:"Linux's victory never just happened in data centers. It happened simultaneously on every embedded circuit board stuffed inside instrument casings, every drone auto-navigating over fields, and every ultrasound probe running real-time image recognition in hospitals. Windows had never reached those places."}),"\n",(0,i.jsx)(n.p,{children:"Here, a mirror image of the pattern identified in Chapter 2 appears\u2014"}),"\n",(0,i.jsxs)(n.p,{children:["DirectX's pattern was: ",(0,i.jsx)(n.strong,{children:"Microsoft used convenience to attract developers into Windows, used API lock-in to bind them, and finally locked in consumers."})]}),"\n",(0,i.jsxs)(n.p,{children:["CUDA on Linux's pattern was: ",(0,i.jsx)(n.strong,{children:"NVIDIA used freedom to attract researchers into CUDA, used ecosystem lock-in to bind them, and finally locked in the entire AI industry."})]}),"\n",(0,i.jsx)(n.p,{children:"The locking mechanism was exactly the same. But the location of the lock was different. Chapter 2's lock was installed on Windows; Chapter 5's lock was installed on Linux. The Windows moat Microsoft spent ten years paving was completely useless on the most important battlefield of AI\u2014because the battlefield wasn't there."}),"\n",(0,i.jsx)(n.p,{children:"In September 2012, two researchers at the University of Toronto\u2014Alex Krizhevsky and his advisors Ilya Sutskever and Geoffrey Hinton\u2014published an image recognition model called AlexNet. It won the ImageNet competition, beating the runner-up by over ten percentage points."}),"\n",(0,i.jsx)(n.p,{children:"AlexNet was trained using two NVIDIA GTX 580 graphics cards. Running CUDA. The operating system was Linux."}),"\n",(0,i.jsxs)(n.p,{children:["Those two GTX 580s retailed for about $500 each. They were originally designed for gamers\u2014to play ",(0,i.jsx)(n.em,{children:"Skyrim"}),", to run ",(0,i.jsx)(n.em,{children:"Battlefield 3"}),". Gamers who bought those cards shared the R&D cost of the Fermi architecture for NVIDIA; the CUDA cores inside the Fermi architecture were used by Krizhevsky to do matrix multiplication; the results of that matrix multiplication ignited the deep learning revolution."]}),"\n",(0,i.jsxs)(n.p,{children:["That is the full story of Chapter 7. But in Chapter 5, the only fact we need to remember is this: ",(0,i.jsx)(n.strong,{children:"At the moment of ignition, Windows wasn't present. Intel wasn't present either."})]}),"\n",(0,i.jsx)(n.p,{children:"They weren't defeated. They walked away on their own."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"v-closing-arguments",children:"V. Closing Arguments"}),"\n",(0,i.jsx)(n.p,{children:'In 2014, Satya Nadella took over as Microsoft CEO. The first thing he did that sent shockwaves through the industry was standing on stage, smiling in front of a slide that read "Microsoft \u2665 Linux."'}),"\n",(0,i.jsx)(n.p,{children:"The tech journalists in the audience laughed out loud. Thirteen years earlier, this company's former CEO had called Linux a cancer."}),"\n",(0,i.jsx)(n.p,{children:"Nadella wasn't doing PR. He was acknowledging reality. More than half the workloads on Azure cloud services ran Linux; all the important frameworks of the AI research community\u2014TensorFlow, PyTorch, JAX\u2014all treated Linux as their primary platform; every company in the world that wanted to do AI was renting GPU clusters running Linux. If Microsoft continued treating Linux as an enemy, its cloud business\u2014the biggest growth engine for the entire company's future\u2014would be completely left behind by AWS and Google Cloud."}),"\n",(0,i.jsx)(n.p,{children:"Nadella's \"Microsoft \u2665 Linux\" was Microsoft's unconditional surrender."}),"\n",(0,i.jsx)(n.p,{children:"But the surrender came too late."}),"\n",(0,i.jsx)(n.p,{children:"The software ecosystem of AI had already entirely grown in the soil of Linux. Every deep learning framework, every set of training tools, every pipeline from data preprocessing to model deployment\u2014all assumed the underlying layer was Linux. This wasn't prejudice; it was engineering reality. The performance of NVIDIA's CUDA toolchain on Linux consistently outperformed Windows; GPU cluster management tools were almost entirely written for Linux; containerization tech (Docker) ran natively on Linux, while on Windows it was just an emulation layer."}),"\n",(0,i.jsx)(n.p,{children:"Microsoft later did a lot to compensate\u2014acquiring GitHub, making WSL (Windows Subsystem for Linux) nearly seamless, investing tens of billions of dollars in OpenAI. Every step of these moves was smart. But they addressed the symptoms, not the disease."}),"\n",(0,i.jsxs)(n.p,{children:["The disease is: ",(0,i.jsx)(n.strong,{children:"When the roots of an ecosystem grow in someone else's soil, you can water them, fertilize them, and build a greenhouse over them\u2014but you can never pull the roots up and transplant them into your own garden."})]}),"\n",(0,i.jsx)(n.p,{children:"Things were even worse for Intel. After Larrabee died, Intel disappeared from the GPU market for a full twelve years. In 2022, it finally launched the consumer discrete graphics Arc series\u2014but in that year, NVIDIA's data center GPU revenue had already surpassed its gaming GPU revenue, and the AI arms race had already reached a boiling point. Intel walked into a missile war carrying a bow and arrow."}),"\n",(0,i.jsx)(n.p,{children:"Back to the Stanford PhD student at the beginning of this chapter."}),"\n",(0,i.jsx)(n.p,{children:'Every day she SSHs from macOS into a Linux cluster, trains models with CUDA, pushes results to GitHub, and tracks experiments with Weights & Biases\u2014in her entire workflow, the role of Windows is zero, and the role of the Intel CPU is "just run preprocessing." She feels this is perfectly natural.'}),"\n",(0,i.jsx)(n.p,{children:"But this isn't natural. It is the delayed bill for three decisions: Ballmer's \"cancer\" comment in 2001, the Intel board's veto in 2010, and Windows' choice since 1993 to hide hardware behind walls."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"The total amount of that bill is the industrial dominance of an entire era."})}),"\n",(0,i.jsx)(n.p,{children:"Microsoft paid this bill\u2014it tried to buy back a torn admission ticket at the cost of tens of billions of dollars in AI investments, reorganization after reorganization, and sacrificing Xbox (the story of Chapter 10)."}),"\n",(0,i.jsx)(n.p,{children:"Intel is still paying. And may never finish paying."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.h2,{id:"vi-the-loot-is-still-being-divided",children:"VI. The Loot is Still Being Divided"}),"\n",(0,i.jsx)(n.p,{children:"Here, we must draw a line connecting Chapter 2 and Chapter 5\u2014because the two sides of the exact same pattern finally converge here."}),"\n",(0,i.jsx)(n.p,{children:"Chapter 2's DirectX was the weapon Microsoft used to lock the PC gaming ecosystem. It succeeded. By the early 2000s, the vast majority of PC games only ran on Windows; developers were locked onto DirectX, and consumers were locked onto Windows."}),"\n",(0,i.jsx)(n.p,{children:"But the wall that locked in gaming had a side effect\u2014it made Windows increasingly closed off. Every new layer of API, every new driver model, every new security mechanism was designed to protect the commercial interests of the previous layer, rather than to let developers touch the hardware. People who needed to touch the hardware\u2014research engineers, HPC engineers, those who would later become AI researchers\u2014weren't driven away by Microsoft's malice; they were forced out by Microsoft's success."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Windows' moat was too deep, so deep that even its own people couldn't get out\u2014and the people outside didn't want to come in."})}),"\n",(0,i.jsx)(n.p,{children:"This is why when AlexNet ignited in 2012, the fire burned on Linux. Not because someone deliberately chose Linux; but because Linux was the only place not locked down by any single company."}),"\n",(0,i.jsx)(n.p,{children:"And once the fire of AI burned on Linux, it never moved again. Because the entire ecosystem brought by the flames\u2014frameworks, tools, communities, educational resources, the job market\u2014all grew on Linux. Even if an ML engineer in 2025 wanted to train models on Windows, she would find: the tutorials are for Linux, the Docker images are for Linux, the latest NVIDIA CUDA version stabilizes on Linux first, and the debugging experience on Stack Overflow is entirely Linux-based."}),"\n",(0,i.jsx)(n.p,{children:"This lock-in effect is exactly the same mechanism as DirectX locking in game developers\u2014only the direction is reversed."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Chapter 2's pattern: Microsoft uses convenience to lock developers \u2192 developers lock consumers \u2192 consumers are locked on Windows."})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"Chapter 5's pattern: Linux uses freedom to attract researchers \u2192 researchers build the ecosystem \u2192 the ecosystem locks the entire AI industry \u2192 the AI industry is locked on Linux."})}),"\n",(0,i.jsx)(n.p,{children:"The cost materialized thirty years later."}),"\n",(0,i.jsx)(n.p,{children:"The Windows moat Microsoft spent thirty years building was perfectly bypassed in the AI era. It wasn't breached\u2014it was bypassed. The besiegers didn't even realize they were taking a detour. They just went to a freer place, and built a bigger city there."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"But AI researchers weren't the only group forced to Linux by Windows' closed nature."}),"\n",(0,i.jsx)(n.p,{children:'In the exact same year Nadella stood on stage and said "Microsoft \u2665 Linux"\u20142014\u2014in another nondescript office building in Seattle, a chubby, slow-speaking former Microsoft employee was staring at a set of data.'}),"\n",(0,i.jsx)(n.p,{children:"The data showed: Microsoft was planning to turn the Windows Store into a closed App Store. All software released on Windows would have to pass Microsoft review, and Microsoft would take a cut. If this came true, his company\u2014a company that lived by selling games on Windows\u2014would turn from a landlord into a tenant."}),"\n",(0,i.jsx)(n.p,{children:'He decided to do something a hundred times more radical than "\u2665 Linux."'}),"\n",(0,i.jsx)(n.p,{children:"He was going to move the entire Windows gaming ecosystem onto Linux. Without modifying a single line of Windows source code. Without asking for Microsoft's permission. Without consulting anyone."}),"\n",(0,i.jsx)(n.p,{children:"His name was Gabe Newell. His plan required a team of full-stack engineers who could write everything from system calls to GPU drivers\u2014because what they needed to do was build a virtual Windows on top of Linux, making tens of thousands of DirectX games believe they were still running in Microsoft's world."}),"\n",(0,i.jsx)(n.p,{children:"This, according to all reasonable engineering judgment, was impossible to achieve."}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.img,{src:t(801).A+"",width:"2816",height:"1536"})})]})}function c(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},801(e,n,t){t.d(n,{A:()=>i});const i=t.p+"assets/images/ch05_en-eba6c6a2bc9319e5b92317985fbcfdbf.png"},8453(e,n,t){t.d(n,{R:()=>r,x:()=>a});var i=t(6540);const s={},o=i.createContext(s);function r(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function a(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);